create table "public"."kihou" (
    -- "id" bigint PRIMARY KEY references companies (id),
    "id" bigint unique not null, 
    "name" text, 
    "tsr_id" text, 
    "description" text,
    "insert_at" timestamp with time zone not null default now()
);


create table "public"."kihou_details" (
  "id" bigint generated by default as identity not null,
  "insert_at" timestamp with time zone default now(),
  "year" serial,
  "code" bigint,
  FOREIGN KEY (code) REFERENCES kihou (id),
  "取引先名" text,
  "順位" text,
  "資材合計S" text,
  "外注合計G" text,
  "全体SG" text,
  "工具" text,
  "軸受" text,
  "油圧" text,
  "ｶｰﾊｲﾄﾞﾛ" text,
  "工作機" text,
  "ﾛﾎﾞｯﾄ" text,
  "ﾏﾃﾘｱﾙ" text,
  "ｻｰﾓ" text,
  "本社" text,
  "関係会社" text,
  "主要" text
);


create table "public"."tsr" (
    "id" bigint PRIMARY KEY references companies (tsr_id),
    "name" text,
    "company_id" bigint, 
    FOREIGN KEY (company_id) REFERENCES companies (id),
    "description" text,
    "insert_at" timestamp with time zone not null default now()
);

